    #{id}

UPDATE pms_sku_stock SET lock_stock = CASE id
WHEN #{item.productSkuId} THEN lock_stock - #{item.productQuantity}
END WHERE id IN
#{item.productSkuId}

UPDATE pms_sku_stock
SET lock_stock = lock_stock + #{quantity}
WHERE
id = #{productSkuId}
AND lock_stock + #{quantity} <= stock


WITH updated_sku AS (
    UPDATE pms_sku_stock s
    SET
        lock_stock = GREATEST(0, s.lock_stock - #{quantity}),
        stock = s.stock - #{quantity},
        sale = s.sale + #{quantity}
    FROM pms_product p
    WHERE
        s.product_id = p.id
      AND s.id = #{productSkuId}
      AND s.stock >= #{quantity}
      AND p.stock >= #{quantity}
    RETURNING s.product_id
)
UPDATE pms_product p
SET
    stock = p.stock - #{quantity},
    sale = p.sale + #{quantity}
FROM updated_sku us
WHERE p.id = us.product_id

UPDATE pms_product
SET
    stock = stock - #{quantity},
    sale = sale + #{quantity}
WHERE
    id = #{productId}
  AND stock >= #{quantity}

UPDATE pms_sku_stock
SET lock_stock = lock_stock - #{quantity}
WHERE
    id = #{productSkuId}
  AND lock_stock - #{quantity} >= 0
